import GeneralChart from "components/UI/Charts/General";
import React from "react";

const graphdata = [
    {
        Year: 2010,
        Income: 1000,
        Expenses: 789
    },
    {
        year: 2011,
        Income: 5000,
        Expenses: 823
    },
    {
        year: 2012,
        Income: 1500,
        Expenses: 233
    },
    {
        year: 2013,
        Income: 3430,
        Expenses: 656
    },
    {
        year: 2014,
        Income: 2800,
        Expenses: 384
    },
    {
        year: 2015,
        Income: 2646,
        Expenses: 445
    },
    {
        year: 2016,
        Income: 4380,
        Expenses: 164
    },
    {
        year: 2017,
        Income: 1900,
        Expenses: 837
    },
    {
        year: 2018,
        Income: 5257,
        Expenses: 659
    },
    {
        year: 2019,
        Income: 2300,
        Expenses: 238
    },
    {
        year: 2020,
        Income: 2475,
        Expenses: 384
    },
]

const PracticeVisualization = () => {

    const optionData = {
        labels: graphdata && graphdata.map((item) => item.Year),
        datasets: [
            {
                label: "Users Gained",
                data: graphdata && graphdata.map((data) => data.Income),
                backgroundColor: ["darkred", "green", "yellow", "blue", "pink", "white", "grey", "orange", "purple", "dark"],
                tension: 0.5,
            },
        ]
    }

    console.log(graphdata)

    return (
        <>
            <div className="row">
                <div className="col-md-9">
                    <GeneralChart minHeight={400} options={optionData} />
                </div>
                <div className="col-md-3 chartOptions">
                    <h6>Select</h6>
                    <p>Visualization Parameters</p>

                    {/* <ul>
          {props.options?.map((item) => (
            <li key={item.id}>
              <CustomCheckBox
                id={"" + item.id}
                label={item.name}
                onChange={(e) => handleSelect(item.id)}
                checked={selected.includes(item.id)}
              />
            </li>
          ))}
        </ul> */}
                </div>
            </div>
        </>
    )
}

export default PracticeVisualization;
